import hashlib
import os

def anonymize_email(email):
    salt = os.urandom(32)
    hash_obj = hashlib.sha256()
    hash_obj.update(salt + email.encode('utf-8'))
    hashed_email = hash_obj.hexdigest()
    return {'salt': salt, 'hashed_email': hashed_email}

def verify_email(email, stored_data):
    hash_obj = hashlib.sha256()
    hash_obj.update(stored_data['salt'] + email.encode('utf-8'))
    hashed_email = hash_obj.hexdigest()
    return hashed_email == stored_data['hashed_email']

interface CacheStrategy<K, V> {
  get(key: K): V | undefined;
  set(key: K, value: V): void;
}

class MapCacheStrategy<K, V> implements CacheStrategy<K, V> {
  private cache = new Map<K, V>();

  get(key: K): V | undefined {
    return this.cache.get(key);
  }

  set(key: K, value: V): void {
    this.cache.set(key, value);
  }
}

function fibonacci(n: number, cacheStrategy: CacheStrategy<number, number> = new MapCacheStrategy()): number {
  if (n <= 1) return n;

  const cached = cacheStrategy.get(n);
  if (cached !== undefined) return cached;

  const result = fibonacci(n - 1, cacheStrategy) + fibonacci(n - 2, cacheStrategy);
  cacheStrategy.set(n, result);
  return result;
}

from enum import Enum, auto


class TCPState(Enum):
    CLOSED = auto()
    LISTEN = auto()
    SYN_SENT = auto()
    SYN_RECEIVED = auto()
    ESTABLISHED = auto()
    FIN_WAIT_1 = auto()
    FIN_WAIT_2 = auto()
    CLOSE_WAIT = auto()
    CLOSING = auto()
    LAST_ACK = auto()
    TIME_WAIT = auto()


class TCPEvent(Enum):
    PASSIVE_OPEN = auto()
    ACTIVE_OPEN = auto()
    SEND = auto()
    RECEIVE_SYN = auto()
    RECEIVE_ACK = auto()
    RECEIVE_SYN_ACK = auto()
    RECEIVE_FIN = auto()
    RECEIVE_FIN_ACK = auto()
    TIMEOUT = auto()
    CLOSE = auto()


class TCPStateMachine:
    def __init__(self):
        self.state = TCPState.CLOSED
        self.transitions = self._build_transitions()

    def _build_transitions(self):
        transitions = {
            TCPState.CLOSED: self._handle_closed_state,
            TCPState.LISTEN: self._handle_listen_state,
            TCPState.SYN_SENT: self._handle_syn_sent_state,
            TCPState.SYN_RECEIVED: self._handle_syn_received_state,
            TCPState.ESTABLISHED: self._handle_established_state,
            TCPState.FIN_WAIT_1: self._handle_fin_wait_1_state,
            TCPState.FIN_WAIT_2: self._handle_fin_wait_2_state,
            TCPState.CLOSE_WAIT: self._handle_close_wait_state,
            TCPState.CLOSING: self._handle_closing_state,
            TCPState.LAST_ACK: self._handle_last_ack_state,
            TCPState.TIME_WAIT: self._handle_time_wait_state,
        }
        return transitions

    def process_event(self, event):
        if self.state in self.transitions:
            handler = self.transitions[self.state]
            handler(event)

    def _handle_closed_state(self, event):
        if event == TCPEvent.PASSIVE_OPEN:
            self.state = TCPState.LISTEN
        elif event == TCPEvent.ACTIVE_OPEN:
            self.state = TCPState.SYN_SENT

    def _handle_listen_state(self, event):
        if event == TCPEvent.RECEIVE_SYN:
            self.state = TCPState.SYN_RECEIVED
        elif event == TCPEvent.CLOSE:
            self.state = TCPState.CLOSED

    def _handle_syn_sent_state(self, event):
        if event == TCPEvent.RECEIVE_SYN:
            self.state = TCPState.SYN_RECEIVED
        elif event == TCPEvent.RECEIVE_SYN_ACK:
            self.state = TCPState.ESTABLISHED
        elif event == TCPEvent.CLOSE:
            self.state = TCPState.CLOSED

    def _handle_syn_received_state(self, event):
        if event == TCPEvent.RECEIVE_ACK:
            self.state = TCPState.ESTABLISHED
        elif event == TCPEvent.CLOSE:
            self.state = TCPState.FIN_WAIT_1

    def _handle_established_state(self, event):
        if event == TCPEvent.CLOSE:
            self.state = TCPState.FIN_WAIT_1
        elif event == TCPEvent.RECEIVE_FIN:
            self.state = TCPState.CLOSE_WAIT

    def _handle_fin_wait_1_state(self, event):
        if event == TCPEvent.RECEIVE_FIN:
            self.state = TCPState.CLOSING
        elif event == TCPEvent.RECEIVE_FIN_ACK:
            self.state = TCPState.TIME_WAIT
        elif event == TCPEvent.RECEIVE_ACK:
            self.state = TCPState.FIN_WAIT_2

    def _handle_fin_wait_2_state(self, event):
        if event == TCPEvent.RECEIVE_FIN:
            self.state = TCPState.TIME_WAIT

    def _handle_close_wait_state(self, event):
        if event == TCPEvent.CLOSE:
            self.state = TCPState.LAST_ACK

    def _handle_closing_state(self, event):
        if event == TCPEvent.RECEIVE_ACK:
            self.state = TCPState.TIME_WAIT

    def _handle_last_ack_state(self, event):
        if event == TCPEvent.RECEIVE_ACK:
            self.state = TCPState.CLOSED

    def _handle_time_wait_state(self, event):
        if event == TCPEvent.TIMEOUT:
            self.state = TCPState.CLOSED

