  async close(): Promise<void> {
    await Promise.all(this.instances.map(instance => instance.close()));
  }
}

// Worker pool for multi-core scaling
class WorkerPool {
  private workerCount: number;
  private pubSub: ScalableKafkaPubSub | null = null;

  constructor(brokers: string[] = ['localhost:9092'], workerCount = os.cpus().length) {
    this.workerCount = workerCount;

    if (cluster.isPrimary) {
      console.log(`Master ${process.pid} is running`);

      // Fork workers
      for (let i = 0; i < this.workerCount; i++) {
        cluster.fork();
      }

      cluster.on('exit', (worker, code, signal) => {
        console.log(`Worker ${worker.process.pid} died. Restarting...`);
        cluster.fork();
      });
    } else {
      // Workers share the Kafka connection
      console.log(`Worker ${process.pid} started`);
      this.pubSub = new ScalableKafkaPubSub(brokers);
    }
  }

  // Methods to be called from the worker processes
  async publish(topic: string, payload: any): Promise<void> {
    if (!this.pubSub) throw new Error('Cannot call publish on master process');
    return this.pubSub.publish(topic, payload);
  }

  async subscribe(topic: string, callback: Function): Promise<void> {
    if (!this.pubSub) throw new Error('Cannot call subscribe on master process');
    return this.pubSub.subscribe(topic, callback);
  }

  async unsubscribe(topic: string, callback: Function): Promise<void> {
    if (!this.pubSub) throw new Error('Cannot call unsubscribe on master process');
    return this.pubSub.unsubscribe(topic, callback);
  }

  async close(): Promise<void> {
    if (this.pubSub) {
      await this.pubSub.close();
    }
  }
}

