package main

import (
	"context"
	"encoding/json"
	"errors"
	"log/slog"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"
)

type Response struct {
	Status  string      `json:"status"`
	Message string      `json:"message,omitempty"`
	Data    interface{} `json:"data,omitempty"`
}

type ExternalService interface {
	FetchData(ctx context.Context) (interface{}, error)
}

type RealExternalService struct {
	URL        string
	HTTPClient *http.Client
}

func (s *RealExternalService) FetchData(ctx context.Context) (interface{}, error) {
	req, err := http.NewRequestWithContext(ctx, http.MethodGet, s.URL, nil)
	if err != nil {
		return nil, err
	}

	resp, err := s.HTTPClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		return nil, errors.New("external API returned non-200 status")
	}

	var data interface{}
	if err := json.NewDecoder(resp.Body).Decode(&data); err != nil {
		return nil, err
	}

	return data, nil
}

type FallbackService struct {
	Primary   ExternalService
	Secondary ExternalService
	Cache     map[string]interface{}
}

func (s *FallbackService) FetchData(ctx context.Context) (interface{}, error) {
	data, err := s.Primary.FetchData(ctx)
	if err == nil {
		s.Cache["data"] = data
		return data, nil
	}

	slog.Error("primary service failed", "error", err)

	data, err = s.Secondary.FetchData(ctx)
	if err == nil {
		return data, nil
	}

	slog.Error("secondary service failed", "error", err)

	if cachedData, ok := s.Cache["data"]; ok {
		slog.Info("using cached data")
		return cachedData, nil
	}

	return nil, errors.New("all services failed and no cache available")
}

func handleRequest(w http.ResponseWriter, r *http.Request, service ExternalService) {
	ctx := r.Context()

	if r.Method != http.MethodGet {
		handleError(w, "method not allowed", http.StatusMethodNotAllowed)
		return
	}

	data, err := service.FetchData(ctx)
	if err != nil {
		handleError(w, "failed to fetch data: "+err.Error(), http.StatusInternalServerError)
		return
	}

	response := Response{
		Status: "success",
		Data:   data,
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	if err := json.NewEncoder(w).Encode(response); err != nil {
		slog.Error("failed to encode response", "error", err)
	}
}

func handleError(w http.ResponseWriter, message string, statusCode int) {
	response := Response{
		Status:  "error",
		Message: message,
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	if err := json.NewEncoder(w).Encode(response); err != nil {
		slog.Error("failed to encode error response", "error", err)
	}
}

func setupLogger() {
	opts := &slog.HandlerOptions{
		Level: slog.LevelInfo,
	}
	handler := slog.NewJSONHandler(os.Stdout, opts)
	logger := slog.New(handler)
	slog.SetDefault(logger)
}

func main() {
	setupLogger()

	httpClient := &http.Client{
		Timeout: 5 * time.Second,
	}

	primaryService := &RealExternalService{
		URL:        "https://api.example.com/data",
		HTTPClient: httpClient,
	}

	secondaryService := &RealExternalService{
		URL:        "https://backup-api.example.com/data",
		HTTPClient: httpClient,
	}

	fallbackService := &FallbackService{
		Primary:   primaryService,
		Secondary: secondaryService,
		Cache:     make(map[string]interface{}),
	}

	mux := http.NewServeMux()
	mux.HandleFunc("/api/data", func(w http.ResponseWriter, r *http.Request) {
		handleRequest(w, r, fallbackService)
	})

	server := &http.Server{
		Addr:    ":8080",
		Handler: mux,
	}

	go func() {
		slog.Info("starting server", "addr", server.Addr)
		if err := server.ListenAndServe(); err != nil && !errors.Is(err, http.ErrServerClosed) {
			slog.Error("server error", "error", err)
			os.Exit(1)
		}
	}()

	stop := make(chan os.Signal, 1)
	signal.Notify(stop, os.Interrupt, syscall.SIGTERM)
	<-stop

	slog.Info("shutting down server")
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := server.Shutdown(ctx); err != nil {
		slog.Error("server shutdown error", "error", err)
	}
}

