import crypto from 'crypto';

interface Transaction {
  id: string;
  timestamp: Date;
  userId: string;
  accountId: string;
  amount: number;
  balanceAfter: number;
  reason: string;
  signature: string;
}

interface TransactionQuery {
  userId?: string;
  accountId?: string;
  startDate?: Date;
  endDate?: Date;
  minAmount?: number;
  maxAmount?: number;
}

class TransactionLedger {
  private transactions: Transaction[] = [];
  private privateKey: crypto.KeyObject;

  constructor(privateKeyPath: string) {
    // In production, load private key securely
    this.privateKey = crypto.createPrivateKey({ key: privateKeyPath, format: 'pem' });
  }

  recordTransaction(
    userId: string,
    accountId: string,
    amount: number, 
    balanceAfter: number,
    reason: string
  ): Transaction {
    const transaction: Omit<Transaction, 'signature'> = {
      id: crypto.randomUUID(),
      timestamp: new Date(),
      userId,
      accountId,
      amount,
      balanceAfter,
      reason
    };

    // Create digital signature of transaction data
    const dataToSign = JSON.stringify(transaction);
    const signature = crypto.sign('sha256', Buffer.from(dataToSign), this.privateKey).toString('base64');

    const signedTransaction: Transaction = {
      ...transaction,
      signature
    };

    this.transactions.push(signedTransaction);
    return signedTransaction;
  }

  verifyTransaction(transaction: Transaction): boolean {
    const { signature, ...transactionData } = transaction;
    const dataToVerify = JSON.stringify(transactionData);
    return crypto.verify(
      'sha256',
      Buffer.from(dataToVerify),
      this.privateKey.export({ type: 'spki', format: 'pem' }),
      Buffer.from(signature, 'base64')
    );
  }

  queryTransactions(query: TransactionQuery, isAdmin: boolean): Transaction[] {
    if (!isAdmin) {
      throw new Error('Only administrators can query transactions');
    }

    return this.transactions.filter(transaction => {
      if (query.userId && transaction.userId !== query.userId) return false;
      if (query.accountId && transaction.accountId !== query.accountId) return false;
      if (query.startDate && transaction.timestamp < query.startDate) return false;
      if (query.endDate && transaction.timestamp > query.endDate) return false;
      if (query.minAmount && transaction.amount < query.minAmount) return false;
      if (query.maxAmount && transaction.amount > query.maxAmount) return false;
      return true;
    });
  }

  exportLedger(isAdmin: boolean): Transaction[] {
    if (!isAdmin) {
      throw new Error('Only administrators can export the full ledger');
    }
    return [...this.transactions];
  }
}

export default TransactionLedger;

