class ConsistentHash:
    def __init__(self, num_virtual_nodes=100):
        self.virtual_nodes = {}  # virtual_node_hash -> physical_node
        self.sorted_keys = []  # sorted list of virtual node hashes
        self.num_virtual_nodes = num_virtual_nodes

    def add_node(self, node):
        for i in range(self.num_virtual_nodes):
            virtual_node = f"{node}:{i}"
            key = self._hash(virtual_node)
            self.virtual_nodes[key] = node
            bisect.insort(self.sorted_keys, key)

    def remove_node(self, node):
        for i in range(self.num_virtual_nodes):
            virtual_node = f"{node}:{i}"
            key = self._hash(virtual_node)
            if key in self.virtual_nodes:
                del self.virtual_nodes[key]
                self.sorted_keys.remove(key)

    def get_node(self, key):
        if not self.sorted_keys:
            return None

        hash_key = self._hash(key)
        idx = bisect.bisect(self.sorted_keys, hash_key)
        if idx == len(self.sorted_keys):
            idx = 0
        return self.virtual_nodes[self.sorted_keys[idx]]

    def get_nodes(self, key, n):
        if not self.sorted_keys:
            return []

        result = []
        hash_key = self._hash(key)
        idx = bisect.bisect(self.sorted_keys, hash_key)
        if idx == len(self.sorted_keys):
            idx = 0

        unique_nodes = set()
        while len(unique_nodes) < n and len(unique_nodes) < len(set(self.virtual_nodes.values())):
            node = self.virtual_nodes[self.sorted_keys[idx]]
            if node not in unique_nodes:
                unique_nodes.add(node)
                result.append(node)
            idx = (idx + 1) % len(self.sorted_keys)

        return result

    def _hash(self, key):
        return int(hashlib.md5(str(key).encode()).hexdigest(), 16)

    def get_node_keys(self, node):
        """Return a list of keys that should belong to this node"""
        return [k for k, v in self.virtual_nodes.items() if v == node]

class GossipProtocol:
    def __init__(self, node_id, host, port, seed_nodes=None):
        self.node_id = node_id
        self.host = host
        self.port = port
        self.nodes = {node_id: {"host": host, "port": port, "last_seen": time.time()}}
        if seed_nodes:
            self.nodes.update(seed_nodes)

        self.suspect_timeout = 10  # seconds
        self.dead_timeout = 30  # seconds
        self.gossip_interval = 1  # seconds

        self.socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
        self.socket.bind((host, port))
        self.socket.settimeout(0.1)

        self.running = True
        self.gossip_thread = threading.Thread(target=self._gossip_loop)
        self.receive_thread = threading.Thread(target=self._receive_loop)
        self.monitor_thread = threading.Thread(target=self._monitor_loop)

        self.callbacks = {
            "node_joined": [],
            "node_left": []
        }

    def start(self):
        self.gossip_thread.start()
        self.receive_thread.start()
        self.monitor_thread.start()

    def stop(self):
        self.running = False
        self.gossip_thread.join()
        self.receive_thread.join()
        self.monitor_thread.join()
        self.socket.close()

    def register_callback(self, event, callback):
        if event in self.callbacks:
            self.callbacks[event].append(callback)

    def _trigger_callbacks(self, event, *args, **kwargs):
        for callback in self.callbacks.get(event, []):
            callback(*args, **kwargs)

    def _gossip_loop(self):
        while self.running:
            live_nodes = {k: v for k, v in self.nodes.items() 
                          if time.time() - v["last_seen"] < self.dead_timeout}

            if len(live_nodes) > 1:  # Don't gossip if I'm the only node
                targets = random.sample(list(live_nodes.keys()), 
                                        min(3, len(live_nodes) - 1))

                for node_id in targets:
                    if node_id != self.node_id:
                        node = live_nodes[node_id]
                        try:
                            message = {
                                "type": "gossip",
                                "source": self.node_id,
                                "nodes": self.nodes
                            }
                            self.socket.sendto(json.dumps(message).encode(), 
                                              (node["host"], node["port"]))
                        except Exception as e:
                            print(f"Error gossiping to {node_id}: {e}")

            time.sleep(self.gossip_interval)

    def _receive_loop(self):
        while self.running:
            try:
                data, addr = self.socket.recvfrom(65536)
                message = json.loads(data.decode())

                if message["type"] == "gossip":
                    source_id = message["source"]
                    received_nodes = message["nodes"]

                    # Update source's last_seen timestamp
                    if source_id in self.nodes:
                        self.nodes[source_id]["last_seen"] = time.time()

                    # Process received node information
                    for node_id, node_info in received_nodes.items():
                        if node_id not in self.nodes:
                            # New node discovered
                            self.nodes[node_id] = node_info
                            self._trigger_callbacks("node_joined", node_id, node_info)
                        else:
                            # Update last_seen if the received info is newer
                            if node_info["last_seen"] > self.nodes[node_id]["last_seen"]:
                                self.nodes[node_id] = node_info

            except socket.timeout:
                pass
            except Exception as e:
                print(f"Error in receive loop: {e}")

    def _monitor_loop(self):
        while self.running:
            current_time = time.time()
            nodes_to_remove = []

            for node_id, node_info in self.nodes.items():
                time_since_last_seen = current_time - node_info["last_seen"]

                if time_since_last_seen > self.dead_timeout:
                    nodes_to_remove.append(node_id)

            for node_id in nodes_to_remove:
                del self.nodes[node_id]
                self._trigger_callbacks("node_left", node_id)

            time.sleep(1)

    def get_live_nodes(self):
        current_time = time.time()
        return {k: v for k, v in self.nodes.items() 
                if current_time - v["last_seen"] < self.dead_timeout}

