        self.gossip.register_callback("node_joined", self._on_node_joined)
        self.gossip.register_callback("node_left", self._on_node_left)

        # Add myself to the ring
        self.ring.add_node(self.node_id)

        # Add seed nodes to the ring
        if seed_nodes:
            for node_id in seed_nodes:
                self.ring.add_node(node_id)

        # Start gossip protocol
        self.gossip.start()

        # Start data redistribution thread
        self.redistribution_thread = threading.Thread(target=self._redistribution_loop)
        self.redistribution_thread.start()

    def put(self, key, value):
        # Find the primary nodes for this key
        target_nodes = self.ring.get_nodes(key, self.replication_factor)

        if not target_nodes:
            return False

        # If I'm one of the target nodes, store locally
        if self.node_id in target_nodes:
            self.local_store[key] = value

        # Forward to other target nodes
        for node_id in target_nodes:
            if node_id != self.node_id:
                # In a real implementation, we would use RPC or HTTP to forward
                # For simplicity, we'll just print
