        target_nodes = self.ring.get_nodes(key, self.replication_factor)

        if not target_nodes:
            return None

        # If I have it locally, return it
        if self.node_id in target_nodes and key in self.local_store:
            return self.local_store[key]

        # In a real implementation, we would query other nodes that have the data
        # For simplicity, we'll just return None
        return None

    def delete(self, key):
        # Find the primary nodes for this key
        target_nodes = self.ring.get_nodes(key, self.replication_factor)

        if not target_nodes:
            return False

        # If I'm one of the target nodes, delete locally
        if self.node_id in target_nodes and key in self.local_store:
            del self.local_store[key]

        # Forward to other target nodes
        for node_id in target_nodes:
            if node_id != self.node_id:
                # In a real implementation, we would use RPC or HTTP to forward
                # For simplicity, we'll just print
                print(f"Would send delete for key {key} to node {node_id}")

        return True

    def _on_node_joined(self, node_id, node_info):
        print(f"Node joined: {node_id}")
        self.ring.add_node(node_id)
        self._redistribute_data()

    def _on_node_left(self, node_id):
        print(f"Node left: {node_id}")
        self.ring.remove_node(node_id)
        self._redistribute_data()

    def _redistribute_data(self):
        # For each key in local store, check if we should still own it
        keys_to_remove = []

        for key in self.local_store:
            target_nodes = self.ring.get_nodes(key, self.replication_factor)

            if self.node_id not in target_nodes:
                # We shouldn't have this key anymore
                # Forward to new owners and remove locally
                for node_id in target_nodes:
                    # In a real implementation, we would use RPC or HTTP to forward
