    const salt = crypto.randomBytes(16);
    const iv = crypto.randomBytes(12);

    // Derive key using PBKDF2
    const key = crypto.pbkdf2Sync(this.encryptionKey, salt, 100000, 32, 'sha256');

    // Create cipher
    const cipher = crypto.createCipherGCM('aes-256-gcm', key);
    cipher.setAAD(Buffer.from('audit-log', 'utf8'));

    // Encrypt
    let encrypted = cipher.update(plaintext, 'utf8');
    encrypted = Buffer.concat([encrypted, cipher.final()]);
    const tag = cipher.getAuthTag();

    return JSON.stringify({
      salt: salt.toString('base64'),
      iv: iv.toString('base64'),
      ciphertext: encrypted.toString('base64'),
      tag: tag.toString('base64')
    });
  }

  decrypt(encryptedData, userAuthLevel) {
    if (userAuthLevel < this.authLevels.ADMIN) {
      throw new Error('Insufficient authorization level for decryption');
    }

    const data = JSON.parse(encryptedData);
    const salt = Buffer.from(data.salt, 'base64');
    const iv = Buffer.from(data.iv, 'base64');
    const ciphertext = Buffer.from(data.ciphertext, 'base64');
    const tag = Buffer.from(data.tag, 'base64');

    // Derive key
    const key = crypto.pbkdf2Sync(this.encryptionKey, salt, 100000, 32, 'sha256');

    // Create decipher
    const decipher = crypto.createDecipherGCM('aes-256-gcm', key);
    decipher.setAAD(Buffer.from('audit-log', 'utf8'));
    decipher.setAuthTag(tag);

    // Decrypt
    let decrypted = decipher.update(ciphertext);
    decrypted = Buffer.concat([decrypted, decipher.final()]);

    return decrypted.toString('utf8');
  }

  generateHMAC(message) {
    const hmac = crypto.createHmac('sha256', this.hmacKey);
    hmac.update(message);
    return hmac.digest();
  }

  validateHMAC(message, receivedHmac) {
    const computedHmac = this.generateHMAC(message);
    const receivedBuffer = Buffer.from(receivedHmac, 'base64');
    return crypto.timingSafeEqual(computedHmac, receivedBuffer);
  }

  addLog(record, userAuthLevel) {
    if (userAuthLevel < this.authLevels.BASIC) {
      throw new Error('Insufficient authorization level');
    }

    // Create a copy to avoid modifying original
    const logRecord = { ...record };

    // Encrypt sensitive fields
    if (logRecord.SSN) {
      logRecord.SSN = this.encrypt(logRecord.SSN);
    }
    if (logRecord.email) {
      logRecord.email = this.encrypt(logRecord.email);
    }

    // Add timestamp and metadata
    logRecord.timestamp = new Date().toISOString();
    logRecord.authLevel = userAuthLevel;

    // Serialize record
    const serializedRecord = JSON.stringify(logRecord);

    // Generate HMAC
    const hmacSignature = this.generateHMAC(serializedRecord);

    // Create final log entry with HMAC
    const logEntry = {
      record: logRecord,
      hmac: hmacSignature.toString('base64')
    };

    return JSON.stringify(logEntry);
  }

  verifyLog(serializedLogEntry, userAuthLevel) {
    if (userAuthLevel < this.authLevels.ADMIN) {
      throw new Error('Insufficient authorization level for log verification');
    }

    try {
      const logEntry = JSON.parse(serializedLogEntry);
      const serializedRecord = JSON.stringify(logEntry.record);

      // Validate HMAC
      if (!this.validateHMAC(serializedRecord, logEntry.hmac)) {
        return { valid: false, error: 'HMAC validation failed - log may be tampered' };
      }

      return { valid: true, record: logEntry.record };
    } catch (error) {
      return { valid: false, error: 'Invalid log format: ' + error.message };
    }
  }

  decryptSensitiveFields(record, userAuthLevel) {
    if (userAuthLevel < this.authLevels.SECURITY_OFFICER) {
      throw new Error('Insufficient authorization level for sensitive field decryption');
    }

    const decryptedRecord = { ...record };

    try {
      if (record.SSN && typeof record.SSN === 'string') {
        decryptedRecord.SSN = this.decrypt(record.SSN, userAuthLevel);
      }
      if (record.email && typeof record.email === 'string') {
        decryptedRecord.email = this.decrypt(record.email, userAuthLevel);
      }
    } catch (error) {
      throw new Error('Decryption failed: ' + error.message);
    }

    return decryptedRecord;
  }

  retrieveLog(serializedLogEntry, userAuthLevel, decryptSensitive = false) {
    // First verify the log
    const verification = this.verifyLog(serializedLogEntry, userAuthLevel);

    if (!verification.valid) {
      throw new Error('Log verification failed: ' + verification.error);
    }

    let record = verification.record;

    // Decrypt sensitive fields if requested and authorized
    if (decryptSensitive) {
      record = this.decryptSensitiveFields(record, userAuthLevel);
    }

