import { S3Client, CreateMultipartUploadCommand, UploadPartCommand, CompleteMultipartUploadCommand, AbortMultipartUploadCommand } from '@aws-sdk/client-s3';
import { createHash } from 'crypto';
import { createReadStream, createWriteStream, promises as fs } from 'fs';
import { pipeline } from 'stream/promises';
import { v4 as uuidv4 } from 'uuid';

interface UploadOptions {
  file: string;
  destination: string;
  bucketName?: string;
  chunkSize?: number;
  maxRetries?: number;
  onProgress?: (progress: number) => void;
}

interface ChunkMetadata {
  id: number;
  start: number;
  end: number;
  checksum: string;
  uploaded: boolean;
}

interface UploadMetadata {
  id: string;
  fileName: string;
  destination: string;
  totalSize: number;
  chunks: ChunkMetadata[];
  completed: boolean;
}

export class UploadService {
  private s3Client: S3Client;
  private tempDir: string;
  private chunkSize: number;
  private maxRetries: number;

  constructor(options: { tempDir?: string; chunkSize?: number; maxRetries?: number; region?: string }) {
    this.tempDir = options.tempDir || './temp';
    this.chunkSize = options.chunkSize || 5 * 1024 * 1024; // 5MB default
    this.maxRetries = options.maxRetries || 3;
    this.s3Client = new S3Client({ region: options.region || 'us-east-1' });
  }

  async upload(options: UploadOptions): Promise<string> {
    const { file, destination, bucketName, chunkSize = this.chunkSize, maxRetries = this.maxRetries, onProgress } = options;

    // Create temp directory if it doesn't exist
    await fs.mkdir(this.tempDir, { recursive: true });

    // Generate upload ID and metadata
    const uploadId = uuidv4();
    const stats = await fs.stat(file);
    const totalSize = stats.size;

    // Calculate number of chunks
    const numChunks = Math.ceil(totalSize / chunkSize);

    // Prepare metadata
    const metadata: UploadMetadata = {
      id: uploadId,
      fileName: file,
      destination,
      totalSize,
      chunks: [],
      completed: false
    };

    // Create chunk metadata
    for (let i = 0; i < numChunks; i++) {
      const start = i * chunkSize;
      const end = Math.min(start + chunkSize, totalSize);
      metadata.chunks.push({
        id: i,
        start,
        end,
        checksum: '',
        uploaded: false
      });
    }

    // Save initial metadata
    await this.saveMetadata(uploadId, metadata);

    // Process chunks
    let completedSize = 0;

    for (const chunk of metadata.chunks) {
      if (!chunk.uploaded) {
        // Calculate checksum for the chunk
        chunk.checksum = await this.calculateChecksum(file, chunk.start, chunk.end);

        // Upload chunk with retries
        let attempt = 0;
        let success = false;

        while (attempt < maxRetries && !success) {
          try {
            if (bucketName) {
              // Use S3 for upload
              await this.uploadChunkToS3(file, chunk, uploadId, bucketName);
            } else {
              // Use local filesystem
              await this.uploadChunkToLocal(file, chunk, uploadId, destination);
            }
            success = true;
            chunk.uploaded = true;
          } catch (error) {
            attempt++;
            if (attempt >= maxRetries) {
              throw new Error(`Failed to upload chunk ${chunk.id} after ${maxRetries} attempts: ${error.message}`);
            }
            // Exponential backoff
            await new Promise(resolve => setTimeout(resolve, 1000 * Math.pow(2, attempt)));
          }
        }
      }

      completedSize += (chunk.end - chunk.start);
      if (onProgress) {
        onProgress(completedSize / totalSize);
      }

      // Update metadata after each chunk
      await this.saveMetadata(uploadId, metadata);
    }

    // Complete the upload
    if (bucketName) {
      await this.completeS3Upload(uploadId, metadata, bucketName);
    } else {
      await this.completeLocalUpload(uploadId, metadata, destination);
    }

    // Mark as completed
    metadata.completed = true;
    await this.saveMetadata(uploadId, metadata);

    // Clean up temp files
    await this.cleanupTempFiles(uploadId);

    return destination;
  }

  private async calculateChecksum(file: string, start: number, end: number): Promise<string> {
    return new Promise((resolve, reject) => {
      const hash = createHash('md5');
      const stream = createReadStream(file, { start, end: end - 1 });

      stream.on('data', (data) => hash.update(data));
      stream.on('end', () => resolve(hash.digest('hex')));
      stream.on('error', reject);
    });
  }

  private async uploadChunkToLocal(file: string, chunk: ChunkMetadata, uploadId: string, destination: string): Promise<void> {
    const chunkPath = `${this.tempDir}/${uploadId}_${chunk.id}`;
    const readStream = createReadStream(file, { start: chunk.start, end: chunk.end - 1 });
    const writeStream = createWriteStream(chunkPath);

    await pipeline(readStream, writeStream);

    // Verify checksum
    const actualChecksum = await this.calculateChecksum(chunkPath, 0, chunk.end - chunk.start);
    if (actualChecksum !== chunk.checksum) {
      throw new Error(`Checksum verification failed for chunk ${chunk.id}`);
    }
  }

  private async uploadChunkToS3(file: string, chunk: ChunkMetadata, uploadId: string, bucketName: string): Promise<void> {
    // Get or create multipart upload
    const s3UploadId = await this.getOrCreateMultipartUpload(uploadId, bucketName, file);

    // Upload part
    const fileStream = createReadStream(file, { start: chunk.start, end: chunk.end - 1 });
    const buffer = await this.streamToBuffer(fileStream);

    const uploadPartCommand = new UploadPartCommand({
      Bucket: bucketName,
      Key: uploadId,
      UploadId: s3UploadId,
      PartNumber: chunk.id + 1,
      Body: buffer,
      ContentMD5: Buffer.from(chunk.checksum, 'hex').toString('base64')
    });

    const response = await this.s3Client.send(uploadPartCommand);

    // Save ETag for completion
    await this.savePartETag(uploadId, chunk.id, response.ETag);
  }

  private async streamToBuffer(stream: NodeJS.ReadableStream): Promise<Buffer> {
    return new Promise((resolve, reject) => {
      const chunks: Buffer[] = [];
      stream.on('data', (chunk) => chunks.push(Buffer.from(chunk)));
      stream.on('end', () => resolve(Buffer.concat(chunks)));
      stream.on('error', reject);
    });
  }

  private async getOrCreateMultipartUpload(uploadId: string, bucketName: string, file: string): Promise<string> {
    try {
      const s3MetadataPath = `${this.tempDir}/${uploadId}_s3metadata`;
      const s3Metadata = await fs.readFile(s3MetadataPath, 'utf8');
      return JSON.parse(s3Metadata).uploadId;
    } catch (error) {
      // Create new multipart upload
      const command = new CreateMultipartUploadCommand({
        Bucket: bucketName,
        Key: uploadId,
        ContentType: 'application/octet-stream',
        Metadata: {
          originalFilename: file.split('/').pop()
        }
      });

      const response = await this.s3Client.send(command);

      // Save S3 upload ID
      await fs.writeFile(
        `${this.tempDir}/${uploadId}_s3metadata`,
        JSON.stringify({ uploadId: response.UploadId })
      );

      return response.UploadId;
    }
  }

  private async savePartETag(uploadId: string, partNumber: number, etag: string): Promise<void> {
    const etagsPath = `${this.tempDir}/${uploadId}_etags`;
    let etags = {};

    try {
      const existingData = await fs.readFile(etagsPath, 'utf8');
      etags = JSON.parse(existingData);
    } catch (error) {
      // File doesn't exist yet
    }

    etags[partNumber] = etag;
    await fs.writeFile(etagsPath, JSON.stringify(etags));
  }

  private async completeS3Upload(uploadId: string, metadata: UploadMetadata, bucketName: string): Promise<void> {
    // Get S3 upload ID
    const s3MetadataPath = `${this.tempDir}/${uploadId}_s3metadata`;
    const s3Metadata = await fs.readFile(s3MetadataPath, 'utf8');
    const s3UploadId = JSON.parse(s3Metadata).uploadId;

    // Get ETags
    const etagsPath = `${this.tempDir}/${uploadId}_etags`;
    const etagsData = await fs.readFile(etagsPath, 'utf8');
    const etags = JSON.parse(etagsData);

    // Prepare parts for completion
    const parts = metadata.chunks.map((chunk, index) => ({
      ETag: etags[index],
      PartNumber: index + 1
    }));

    // Complete multipart upload
    const completeCommand = new CompleteMultipartUploadCommand({
      Bucket: bucketName,
      Key: uploadId,
      UploadId: s3UploadId,
      MultipartUpload: { Parts: parts }
    });

    await this.s3Client.send(completeCommand);
  }

  private async completeLocalUpload(uploadId: string, metadata: UploadMetadata, destination: string): Promise<void> {
    // Create destination directory if it doesn't exist
    const destDir = destination.split('/').slice(0, -1).join('/');
    await fs.mkdir(destDir, { recursive: true });

    // Create a temporary file for atomic write
    const tempDestination = `${destination}.${uploadId}.tmp`;
    const writeStream = createWriteStream(tempDestination);

    // Concatenate all chunks in order
    for (let i = 0; i < metadata.chunks.length; i++) {
      const chunkPath = `${this.tempDir}/${uploadId}_${i}`;
      const readStream = createReadStream(chunkPath);
      await pipeline(readStream, writeStream, { end: false });
    }

    writeStream.end();

    // Wait for stream to finish
    await new Promise<void>((resolve, reject) => {
      writeStream.on('finish', resolve);
      writeStream.on('error', reject);
    });

    // Atomic rename
    await fs.rename(tempDestination, destination);
  }

  private async saveMetadata(uploadId: string, metadata: UploadMetadata): Promise<void> {
    const metadataPath = `${this.tempDir}/${uploadId}_metadata`;
    await fs.writeFile(metadataPath, JSON.stringify(metadata));
  }

  private async cleanupTempFiles(uploadId: string): Promise<void> {
    const files = await fs.readdir(this.tempDir);
    const uploadFiles = files.filter(file => file.startsWith(uploadId));

    for (const file of uploadFiles) {
      await fs.unlink(`${this.tempDir}/${file}`);
    }
  }

  async resumeUpload(uploadId: string, options?: Partial<UploadOptions>): Promise<string> {
    // Load metadata
    const metadataPath = `${this.tempDir}/${uploadId}_metadata`;
    const metadataJson = await fs.readFile(metadataPath, 'utf8');
    const metadata: UploadMetadata = JSON.parse(metadataJson);

    // If already completed, return destination
    if (metadata.completed) {
      return metadata.destination;
    }

    // Resume upload with merged options
    return this.upload({
      file: metadata.fileName,
      destination: metadata.destination,
      ...(options || {})
    });
  }

  async cancelUpload(uploadId: string, bucketName?: string): Promise<void> {
    try {
      // Load metadata
      const metadataPath = `${this.tempDir}/${uploadId}_metadata`;
      const metadataJson = await fs.readFile(metadataPath, 'utf8');
      const metadata: UploadMetadata = JSON.parse(metadataJson);

      // If S3 upload, abort multipart upload
      if (bucketName) {
        try {
          const s3MetadataPath = `${this.tempDir}/${uploadId}_s3metadata`;
          const s3Metadata = await fs.readFile(s3MetadataPath, 'utf8');
          const s3UploadId = JSON.parse(s3Metadata).uploadId;

          const abortCommand = new AbortMultipartUploadCommand({
            Bucket: bucketName,
            Key: uploadId,
            UploadId: s3UploadId
