const WebSocket = require('ws');
const http = require('http');
const Redis = require('ioredis');
const ConsistentHashing = require('consistent-hashing');
const os = require('os');
const cluster = require('cluster');
const { v4: uuidv4 } = require('uuid');

// Node configuration
const NODE_ID = process.env.NODE_ID || uuidv4();
const PORT = process.env.PORT || 3000;
const REDIS_URL = process.env.REDIS_URL || 'redis://localhost:6379';
const VIRTUAL_NODES = 100; // Number of virtual nodes per physical node

// Redis clients
const redisSubscriber = new Redis(REDIS_URL);
const redisPublisher = new Redis(REDIS_URL);

// Consistent hashing ring
const ring = new ConsistentHashing([NODE_ID], { replicas: VIRTUAL_NODES });

// Connected clients
const clients = new Map();

// Create HTTP server
const server = http.createServer();

// Create WebSocket server
const wss = new WebSocket.Server({ server, maxPayload: 1024 * 1024 });

// Handle new WebSocket connections
wss.on('connection', (ws, req) => {
  const clientId = uuidv4();
  const clientIp = req.socket.remoteAddress;

  // Determine which node should handle this client
  const responsibleNode = ring.getNode(clientId);

  // If this client should be handled by another node, redirect
  if (responsibleNode !== NODE_ID) {
    ws.close(1008, `Redirect:${responsibleNode}`);
    return;
  }

  // Add client to local map
  clients.set(clientId, ws);

  // Connection info
  console.log(`Client ${clientId} connected from ${clientIp}. Total clients: ${clients.size}`);

  // Handle client messages
  ws.on('message', (message) => {
    try {
      const data = JSON.parse(message);

      // If message has a target, route to specific client/channel
      if (data.target) {
        const targetNode = ring.getNode(data.target);

        // If target is on this node, send directly
        if (targetNode === NODE_ID && clients.has(data.target)) {
          const targetClient = clients.get(data.target);
          if (targetClient.readyState === WebSocket.OPEN) {
            targetClient.send(JSON.stringify(data));
          }
        } 
        // Otherwise publish to Redis for other nodes
        else {
          redisPublisher.publish('messages', JSON.stringify({
            source: clientId,
            data: data,
            node: targetNode
          }));
        }
      } 
      // Broadcast message
      else if (data.broadcast) {
        // Broadcast locally
        clients.forEach((client) => {
          if (client.readyState === WebSocket.OPEN) {
            client.send(JSON.stringify(data));
          }
        });

        // Broadcast to other nodes
        redisPublisher.publish('broadcast', JSON.stringify({
          source: clientId,
          data: data
        }));
      }
    } catch (err) {
      console.error(`Error handling message from ${clientId}:`, err);
    }
  });

  // Handle disconnection
  ws.on('close', () => {
    clients.delete(clientId);
    console.log(`Client ${clientId} disconnected. Total clients: ${clients.size}`);
  });
});

// Subscribe to Redis channels
redisSubscriber.subscribe('messages', 'broadcast', 'node:join', 'node:leave');

// Handle Redis messages
redisSubscriber.on('message', (channel, message) => {
  try {
    const data = JSON.parse(message);

    switch (channel) {
      case 'messages':
        // Only process messages targeted for this node
        if (data.node === NODE_ID && clients.has(data.data.target)) {
          const targetClient = clients.get(data.data.target);
          if (targetClient.readyState === WebSocket.OPEN) {
            targetClient.send(JSON.stringify(data.data));
          }
        }
        break;

      case 'broadcast':
        // Broadcast to all local clients
        clients.forEach((client) => {
          if (client.readyState === WebSocket.OPEN) {
            client.send(JSON.stringify(data.data));
          }
        });
        break;

      case 'node:join':
        // Add new node to the ring
        if (data.nodeId !== NODE_ID) {
          ring.addNode(data.nodeId);
          console.log(`Node ${data.nodeId} joined the cluster`);
          rebalanceClients();
        }
        break;

      case 'node:leave':
        // Remove node from the ring
        if (data.nodeId !== NODE_ID) {
          ring.removeNode(data.nodeId);
          console.log(`Node ${data.nodeId} left the cluster`);
          rebalanceClients();
        }
        break;
    }
  } catch (err) {
    console.error('Error handling Redis message:', err);
  }
});

// Announce this node to the cluster
function announceNode() {
  redisPublisher.publish('node:join', JSON.stringify({ nodeId: NODE_ID }));

  // Register node in Redis with TTL
  redisPublisher.setex(`nodes:${NODE_ID}`, 30, JSON.stringify({
    id: NODE_ID,
    host: os.hostname(),
    port: PORT,
    clients: clients.size,
    started: Date.now()
  }));
}

// Handle node shutdown
function gracefulShutdown() {
  console.log('Node shutting down...');

  // Announce departure
  redisPublisher.publish('node:leave', JSON.stringify({ nodeId: NODE_ID }));

  // Close all client connections
  clients.forEach((client) => {
    client.close(1001, 'Server shutting down');
  });

  // Clean up Redis
  redisPublisher.del(`nodes:${NODE_ID}`);

  // Close Redis connections
  redisSubscriber.quit();
  redisPublisher.quit();

  // Close server
  server.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
}

// Rebalance clients when ring changes
function rebalanceClients() {
  console.log('Rebalancing clients...');

  // Check each client
  clients.forEach((ws, clientId) => {
    const responsibleNode = ring.getNode(clientId);

    // If client should move to another node
    if (responsibleNode !== NODE_ID) {
      // Notify client to reconnect elsewhere
      if (ws.readyState === WebSocket.OPEN) {
        ws.send(JSON.stringify({
          type: 'redirect',
          nodeId: responsibleNode
        }));

        // Close connection
        setTimeout(() => {
          ws.close(1008, `Redirect:${responsibleNode}`);
          clients.delete(clientId);
        }, 500);
      }
    }
  });
}

// Start server
server.listen(PORT, () => {
  console.log(`WebSocket server running on port ${PORT} with node ID ${NODE_ID}`);

  // Register heartbeat
  setInterval(() => {
    redisPublisher.setex(`nodes:${NODE_ID}`, 30, JSON.stringify({
      id: NODE_ID,
      host: os.hostname(),
      port: PORT,
      clients: clients.size,
      updated: Date.now()
    }));
  }, 10000);

  // Announce node to cluster
  announceNode();
});

// Handle process signals
process.on('SIGINT', gracefulShutdown);
process.on('SIGTERM', gracefulShutdown);

