import argparse
import os
import time
from typing import List, Dict, Optional

import rich
from rich.console import Console
from rich.table import Table
from rich.syntax import Syntax
from rich.prompt import Prompt, Confirm
from rich.progress import Progress, track
from prompt_toolkit import PromptSession
from prompt_toolkit.completion import WordCompleter
from prompt_toolkit.lexers import PygmentsLexer
from pygments.lexers.sql import SqlLexer
import sqlparse
import sqlite3

console = Console()
undo_stack = []

class Migration:
    def __init__(self, name: str, query: str):
        self.name = name
        self.query = query
        self.applied = False
        self.timestamp = None

    def apply(self, conn, dry_run=False):
        if not dry_run:
            cursor = conn.cursor()
            try:
                cursor.executescript(self.query)
                conn.commit()
                self.applied = True
                self.timestamp = time.time()
                undo_stack.append(self)
                return True
            except Exception as e:
                conn.rollback()
                console.print(f"[bold red]Error:[/bold red] {e}")
                return False
        else:
            console.print("[bold yellow]Dry run - not executing query[/bold yellow]")
            return True

    def rollback(self, conn):
        # In a real implementation, this would execute a rollback script
        console.print(f"Rolling back migration: {self.name}")
        self.applied = False
        return True

def validate_query(query: str) -> bool:
    try:
        parsed = sqlparse.parse(query)
        return len(parsed) > 0
    except:
        return False

def display_migrations(migrations: List[Migration]):
    table = Table(title="Available Migrations")
    table.add_column("Name", style="cyan")
    table.add_column("Status", style="green")
    table.add_column("Applied At", style="magenta")

    for migration in migrations:
        status = "[green]Applied[/green]" if migration.applied else "[yellow]Pending[/yellow]"
        timestamp = time.strftime('%Y-%m-%d %H:%M:%S', time.localtime(migration.timestamp)) if migration.timestamp else "-"
        table.add_row(migration.name, status, timestamp)

    console.print(table)

def preview_query(query: str):
    syntax = Syntax(query, "sql", theme="monokai", line_numbers=True)
    console.print("[bold blue]Query Preview:[/bold blue]")
    console.print(syntax)

def get_connection():
    # Create or connect to SQLite database
    if not os.path.exists("migrations"):
        os.makedirs("migrations")
    conn = sqlite3.connect("migrations/migrations.db")
    conn.execute('''CREATE TABLE IF NOT EXISTS migrations
                 (name TEXT PRIMARY KEY, query TEXT, applied INTEGER, timestamp REAL)''')
    return conn

def main():
    parser = argparse.ArgumentParser(description="Database Migration CLI Tool")
    parser.add_argument("--init", action="store_true", help="Initialize migration database")
    parser.add_argument("--create", help="Create a new migration")
    parser.add_argument("--apply", help="Apply a specific migration")
    parser.add_argument("--apply-all", action="store_true", help="Apply all pending migrations")
    parser.add_argument("--rollback", help="Rollback a specific migration")
    parser.add_argument("--list", action="store_true", help="List all migrations")
    parser.add_argument("--dry-run", action="store_true", help="Preview migrations without applying them")

    args = parser.parse_args()
    conn = get_connection()

    # Load existing migrations
    migrations: Dict[str, Migration] = {}
    cursor = conn.cursor()
    for row in cursor.execute("SELECT name, query, applied, timestamp FROM migrations"):
        migration = Migration(row[0], row[1])
        migration.applied = bool(row[2])
        migration.timestamp = row[3]
        migrations[migration.name] = migration

    if args.init:
        console.print("[bold green]Migration database initialized[/bold green]")

    elif args.create:
        session = PromptSession(lexer=PygmentsLexer(SqlLexer))
        console.print(f"[bold]Creating migration: {args.create}[/bold]")
        console.print("Enter SQL query (press Enter followed by Ctrl+D to finish):")

        lines = []
        while True:
            try:
                line = session.prompt('> ')
                lines.append(line)
            except EOFError:
                break

        query = '\n'.join(lines)

        if validate_query(query):
            migration = Migration(args.create, query)
            cursor.execute("INSERT INTO migrations VALUES (?, ?, ?, ?)", 
                          (migration.name, migration.query, migration.applied, migration.timestamp))
            conn.commit()
            console.print(f"[bold green]Migration '{args.create}' created successfully[/bold green]")
            preview_query(query)
        else:
            console.print("[bold red]Invalid SQL query[/bold red]")

    elif args.apply:
        if args.apply in migrations:
            migration = migrations[args.apply]
            preview_query(migration.query)

            if args.dry_run or Confirm.ask("Apply this migration?"):
                with Progress() as progress:
                    task = progress.add_task("[green]Applying migration...", total=100)

                    for i in range(0, 101, 10):
                        progress.update(task, completed=i)
                        time.sleep(0.1)

                    if migration.apply(conn, args.dry_run):
                        if not args.dry_run:
                            cursor.execute("UPDATE migrations SET applied=?, timestamp=? WHERE name=?", 
                                          (True, migration.timestamp, migration.name))
                            conn.commit()
                        console.print(f"[bold green]Migration '{args.apply}' applied successfully[/bold green]")
                    else:
                        console.print(f"[bold red]Failed to apply migration '{args.apply}'[/bold red]")
        else:
            console.print(f"[bold red]Migration '{args.apply}' not found[/bold red]")

    elif args.apply_all:
        pending_migrations = [m for m in migrations.values() if not m.applied]

        if not pending_migrations:
            console.print("[yellow]No pending migrations[/yellow]")
            return

        for migration in track(pending_migrations, description="Applying migrations"):
            preview_query(migration.query)

            if args.dry_run or Confirm.ask(f"Apply migration '{migration.name}'?"):
                if migration.apply(conn, args.dry_run):
                    if not args.dry_run:
                        cursor.execute("UPDATE migrations SET applied=?, timestamp=? WHERE name=?", 
                                      (True, migration.timestamp, migration.name))
                        conn.commit()
                    console.print(f"[bold green]Migration '{migration.name}' applied successfully[/bold green]")
                else:
                    console.print(f"[bold red]Failed to apply migration '{migration.name}'[/bold red]")
                    break

    elif args.rollback:
        if args.rollback in migrations:
            migration = migrations[args.rollback]

            if migration.applied:
                if Confirm.ask(f"Rollback migration '{args.rollback}'?"):
                    if migration.rollback(conn):
                        cursor.execute("UPDATE migrations SET applied=0, timestamp=NULL WHERE name=?", 
                                      (migration.name,))
                        conn.commit()
                        console.print(f"[bold green]Migration '{args.rollback}' rolled back successfully[/bold green]")
                    else:
                        console.print(f"[bold red]Failed to rollback migration '{args.rollback}'[/bold red]")
            else:
                console.print(f"[yellow]Migration '{args.rollback}' is not applied[/yellow]")
        else:
