                            time.sleep(0.1)

                        if migration.apply(conn):
                            cursor.execute("UPDATE migrations SET applied=?, timestamp=? WHERE name=?", 
                                          (True, migration.timestamp, migration.name))
                            conn.commit()
                            console.print(f"[bold green]Migration '{migration_name}' applied successfully[/bold green]")
                        else:
