package httplogparser

import (
	"bufio"
	"compress/gzip"
	"io"
	"os"
	"regexp"
	"sync"
	"sync/atomic"
)

var (
	logPattern = regexp.MustCompile(`^(\S+) \S+ \S+ \[([^:]+):(\d+:\d+:\d+) ([^\]]+)\] "(\S+) (.*?) (\S+)" (\d+) (\d+)`)
	bufPool    = sync.Pool{
		New: func() interface{} {
			return make([]byte, 0, 4096)
		},
	}
)

type LogEntry struct {
	IP        string
	Timestamp string
	Method    string
	Path      string
	Protocol  string
	Status    string
	Bytes     string
}

type Parser struct {
	NumWorkers int
	processed  int64
}

func NewParser(numWorkers int) *Parser {
	if numWorkers <= 0 {
		numWorkers = 1
	}
	return &Parser{
		NumWorkers: numWorkers,
	}
}

func (p *Parser) ParseFile(filename string) (int64, error) {
	file, err := os.Open(filename)
	if err != nil {
		return 0, err
	}
	defer file.Close()

	gzipReader, err := gzip.NewReader(file)
	if err != nil {
		return 0, err
	}
	defer gzipReader.Close()

	atomic.StoreInt64(&p.processed, 0)
	workChan := make(chan []byte, p.NumWorkers*2)
	doneChan := make(chan struct{})

	// Start worker goroutines
	var wg sync.WaitGroup
	wg.Add(p.NumWorkers)
	for i := 0; i < p.NumWorkers; i++ {
		go func() {
			defer wg.Done()
			for line := range workChan {
				if logPattern.Match(line) {
					atomic.AddInt64(&p.processed, 1)
				}
				bufPool.Put(line[:0]) // Return buffer to pool
			}
		}()
	}

	// Close work channel when all processing is done
	go func() {
		wg.Wait()
		close(doneChan)
	}()

	// Read and distribute work
	scanner := bufio.NewScanner(gzipReader)
	scanner.Buffer(make([]byte, 0, 1024*1024), 10*1024*1024) // 10MB max line size

	for scanner.Scan() {
		buf := bufPool.Get().([]byte)
		buf = append(buf[:0], scanner.Bytes()...)
		workChan <- buf
	}

	close(workChan)
	<-doneChan

	if err := scanner.Err(); err != nil {
		return atomic.LoadInt64(&p.processed), err
	}

	return atomic.LoadInt64(&p.processed), nil
}

func (p *Parser) ProcessedLines() int64 {
	return atomic.LoadInt64(&p.processed)
}

