from app.services.user_service import UserService
from app.services.product_service import ProductService
from app.api.user_routes import create_user_blueprint
from app.api.product_routes import create_product_blueprint

def register_blueprints(app: Flask) -> None:
    """Register all blueprints with the app."""
    # Set up repositories
    user_repository = UserRepository()
    product_repository = ProductRepository()

    # Set up services with DI
    user_service = UserService(user_repository)
    product_service = ProductService(product_repository)

    # Create and register blueprints
    user_bp = create_user_blueprint(user_service)
    product_bp = create_product_blueprint(product_service)

    app.register_blueprint(user_bp, url_prefix='/api')
    app.register_blueprint(product_bp, url_prefix='/api')

