package com.example.cleanarchitecture.domain.service;

import com.example.cleanarchitecture.domain.model.User;
import com.example.cleanarchitecture.domain.repository.UserRepository;
import lombok.RequiredArgsConstructor;
import org.springframework.stereotype.Service;

import java.util.List;
import java.util.Optional;

/**
 * Domain service that encapsulates business logic related to Users.
 * Contains the core business rules and domain logic.
 */
@Service
@RequiredArgsConstructor
public class UserDomainService {

    private final UserRepository userRepository;

    /**
     * Finds a user by their ID.
     *
     * @param id The ID of the user to find
     * @return An Optional containing the user if found
     */
    public Optional<User> getUserById(Long id) {
        return userRepository.findById(id);
    }

    /**
     * Retrieves all users in the system.
     *
     * @return A list of all users
     */
    public List<User> getAllUsers() {
        return userRepository.findAll();
    }

    /**
     * Creates a new user after validating their information.
     *
     * @param user The user to create
     * @return The created user with an assigned ID
     * @throws IllegalArgumentException if the email is already in use
     */
    public User createUser(User user) {
        // Domain validation
        if (user.getEmail() == null || user.getEmail().trim().isEmpty()) {
            throw new IllegalArgumentException("Email cannot be empty");
        }

        // Check if email is already in use
        Optional<User> existingUser = userRepository.findByEmail(user.getEmail());
        if (existingUser.isPresent()) {
            throw new IllegalArgumentException("Email is already in use");
        }

        return userRepository.save(user);
    }

    /**
     * Updates an existing user's information.
     *
     * @param id The ID of the user to update
     * @param user The updated user information
     * @return The updated user if found, or empty if not found
     * @throws IllegalArgumentException if the email is already in use by another user
     */
    public Optional<User> updateUser(Long id, User user) {
        return userRepository.findById(id).map(existingUser -> {
            // Ensure we're updating the correct user
            user.setId(id);

            // If email is changing, check that it's not already in use
            if (!existingUser.getEmail().equals(user.getEmail())) {
                userRepository.findByEmail(user.getEmail()).ifPresent(u -> {
                    if (!u.getId().equals(id)) {
                        throw new IllegalArgumentException("Email is already in use");
                    }
                });
            }

            return userRepository.save(user);
        });
    }

    /**
     * Deletes a user by their ID.
     *
     * @param id The ID of the user to delete
     * @return true if the user was deleted, false if user was not found
     */
    public boolean deleteUser(Long id) {
        return userRepository.deleteById(id);
    }
}

