package com.example.cleanarchitecture.infrastructure.persistence;

import com.example.cleanarchitecture.domain.model.User;
import com.example.cleanarchitecture.domain.repository.UserRepository;
import org.springframework.stereotype.Repository;

import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;
import java.util.Optional;
import java.util.concurrent.atomic.AtomicLong;
import java.util.stream.Collectors;

/**
 * Implementation of the UserRepository interface.
 * Provides a persistence mechanism for User entities.
 * For simplicity, this implementation uses an in-memory data store.
 * In a real application, this would use JPA, JDBC, or another persistence technology.
 */
@Repository
public class UserRepositoryImpl implements UserRepository {

    private final Map<Long, User> users = new HashMap<>();
    private final Map<String, User> usersByEmail = new HashMap<>();
    private final AtomicLong idGenerator = new AtomicLong(1);

    /**
     * {@inheritDoc}
     */
    @Override
    public Optional<User> findById(Long id) {
        return Optional.ofNullable(users.get(id));
    }

    /**
     * {@inheritDoc}
     */
    @Override
    public List<User> findAll() {
        return new ArrayList<>(users.values());
    }

    /**
     * {@inheritDoc}
     */
    @Override
    public User save(User user) {
        // If this is a new user, assign an ID
        if (user.getId() == null) {
            user.setId(idGenerator.getAndIncrement());
        } else {
            // If we're updating an existing user, remove the old email mapping
            Optional<User> existingUser = findById(user.getId());
            existingUser.ifPresent(u -> usersByEmail.remove(u.getEmail()));
        }

        // Save the user
        users.put(user.getId(), user);
        usersByEmail.put(user.getEmail(), user);

        return user;
    }

    /**
     * {@inheritDoc}
     */
    @Override
    public boolean deleteById(Long id) {
        User removedUser = users.remove(id);
        if (removedUser != null) {
            usersByEmail.remove(removedUser.getEmail());
            return true;
        }
        return false;
    }

    /**
     * {@inheritDoc}
     */
    @Override
    public Optional<User> findByEmail(String email) {
        return Optional.ofNullable(usersByEmail.get(email));
    }
}

