package com.example.cleanarchitecture.adapter.api;

import com.example.cleanarchitecture.application.dto.UserDTO;
import com.example.cleanarchitecture.application.service.UserApplicationService;
import io.swagger.annotations.Api;
import io.swagger.annotations.ApiOperation;
import io.swagger.annotations.ApiParam;
import io.swagger.annotations.ApiResponse;
import io.swagger.annotations.ApiResponses;
import lombok.RequiredArgsConstructor;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import javax.validation.Valid;
import java.util.List;

/**
 * REST controller for user operations.
 * Exposes the API endpoints for user management.
 */
@RestController
@RequestMapping("/api/users")
@RequiredArgsConstructor
@Api(tags = "User Management", description = "Operations for managing users")
public class UserController {

    private final UserApplicationService userApplicationService;

    /**
     * Retrieves a user by their ID.
     *
     * @param id The ID of the user to retrieve
     * @return ResponseEntity containing the user if found, or 404 if not found
     */
    @GetMapping("/{id}")
    @ApiOperation(value = "Get a user by ID", notes = "Retrieves a user based on their unique identifier")
    @ApiResponses({
        @ApiResponse(code = 200, message = "User found"),
        @ApiResponse(code = 404, message = "User not found")
    })
    public ResponseEntity<UserDTO> getUserById(
            @ApiParam(value = "User ID", required = true) @PathVariable Long id) {
        return userApplicationService.getUserById(id)
                .map(ResponseEntity::ok)
                .orElse(ResponseEntity.notFound().build());
    }

    /**
     * Retrieves all users.
     *
     * @return A list of all users
     */
    @GetMapping
    @ApiOperation(value = "Get all users", notes = "Retrieves a list of all users in the system")
    @ApiResponse(code = 200, message = "List of users")
    public ResponseEntity<List<UserDTO>> getAllUsers() {
        List<UserDTO> users = userApplicationService.getAllUsers();
        return ResponseEntity.ok(users);
    }

    /**
     * Creates a new user.
     *
     * @param userDTO The user information to create
     * @return ResponseEntity containing the created user
     */
    @PostMapping
    @ResponseStatus(HttpStatus.CREATED)
    @ApiOperation(value = "Create a user", notes = "Creates a new user with the provided information")
    @ApiResponses({
        @ApiResponse(code = 201, message = "User created successfully"),
        @ApiResponse(code = 400, message = "Invalid input or email already in use")
    })
    public ResponseEntity<UserDTO> createUser(
            @ApiParam(value = "User information", required = true) @Valid @RequestBody UserDTO userDTO) {
        try {
            UserDTO createdUser = userApplicationService.createUser(userDTO);
            return ResponseEntity.status(HttpStatus.CREATED).body(createdUser);
        } catch (IllegalArgumentException e) {
            return ResponseEntity.badRequest().build();
        }
    }

    /**
     * Updates an existing user.
     *
     * @param id The ID of the user to update
     * @param userDTO The updated user information
     * @return ResponseEntity containing the updated user if found, or 404 if not found
     */
    @PutMapping("/{id}")
    @ApiOperation(value = "Update a user", notes = "Updates an existing user with the provided information")
    @ApiResponses({
        @ApiResponse(code = 200, message = "User updated successfully"),
        @ApiResponse(code = 400, message = "Invalid input or email already in use"),
        @ApiResponse(code = 404, message = "User not found")
    })
    public ResponseEntity<UserDTO> updateUser(
            @ApiParam(value = "User ID", required = true) @PathVariable Long id,
            @ApiParam(value = "Updated user information", required = true) @Valid @RequestBody UserDTO userDTO) {
        try {
            return userApplicationService.updateUser(id, userDTO)
                    .map(ResponseEntity::ok)
                    .orElse(ResponseEntity.notFound().build());
        } catch (IllegalArgumentException e) {
            return ResponseEntity.badRequest().build();
        }
    }

    /**
     * Deletes a user by their ID.
     *
     * @param id The ID of the user to delete
     * @return ResponseEntity with no content if deleted, or 404 if not found
     */
    @DeleteMapping("/{id}")
    @ApiOperation(value = "Delete a user", notes = "Deletes a user based on their unique identifier")
    @ApiResponses({
        @ApiResponse(code = 204, message = "User deleted successfully"),
        @ApiResponse(code = 404, message = "User not found")
    })
    public ResponseEntity<Void> deleteUser(
            @ApiParam(value = "User ID", required = true) @PathVariable Long id) {
        boolean deleted = userApplicationService.deleteUser(id);
        return deleted 
                ? ResponseEntity.noContent().build() 
                : ResponseEntity.notFound().build();
    }
}

