        std::priority_queue<std::reference_wrapper<ChunkFile>, 
                          std::vector<std::reference_wrapper<ChunkFile>>, 
                          decltype(comparator)> pq(comparator);

        for (auto& cf : chunkFiles) {
            if (cf.valid) {
                pq.push(std::ref(cf));
            }
        }

        // Open output file with buffer
        std::ofstream output(outputFile, std::ios::binary);
        std::vector<char> outputBuffer(BUFFER_SIZE);
        output.rdbuf()->pubsetbuf(outputBuffer.data(), BUFFER_SIZE);

        if (!output) {
            throw std::runtime_error("Could not create output file: " + outputFile);
        }

        // Use batched writing for better performance
        std::vector<Record> outputBatch;
        outputBatch.reserve(BUFFER_SIZE / sizeof(Record));

        // Merge
        while (!pq.empty()) {
            ChunkFile& current = pq.top();

            // Add the current smallest record to output batch
            outputBatch.push_back(current.current);

            // If batch is full, write it
            if (outputBatch.size() >= outputBatch.capacity()) {
                output.write(reinterpret_cast<const char*>(outputBatch.data()), 
                           outputBatch.size() * sizeof(Record));
                outputBatch.clear();
            }

            pq.pop();

            // Read the next record from the file
            if (current.stream.read(reinterpret_cast<char*>(&current.current), sizeof(Record))) {
                pq.push(std::ref(current));
