        }

        // Write any remaining records in the batch
        if (!outputBatch.empty()) {
            output.write(reinterpret_cast<const char*>(outputBatch.data()), 
                       outputBatch.size() * sizeof(Record));
        }

        // Close files
        output.close();
        for (auto& cf : chunkFiles) {
            cf.stream.close();
        }
