        std::cout << "Total Time:       " << totalTime.count() << " s" << std::endl;
        std::cout << "Throughput:       " << throughput << " GB/s" << std::endl;
        std::cout << "I/O Wait Time:    " << ioTime << " s (" << ioPercentage << "% of total)" << std::endl;
        std::cout << "CPU Utilization:  " << 100.0 - ioPercentage << "%" << std::endl;
        std::cout << "Threads Used:     " << numThreads << std::endl;
        std::cout << "=========================================" << std::endl;
    }
};

