            }

            // Exclude current item
            branch_and_bound(node_idx + 1, curr_weight, curr_value, items, capacity, max_value);
        }

        let mut max_value = 0;
        branch_and_bound(0, 0, 0, &items, capacity, &mut max_value);
        max_value
    }
}

// Greedy implementation of the knapsack solver
pub struct GreedySolver;

impl KnapsackSolver for GreedySolver {
    fn solve(&self, weights: &[usize], values: &[usize], capacity: usize) -> usize {
        // Handle edge cases
        if weights.is_empty() || capacity == 0 {
            return 0;
        }

        // Create a vector of (weight, value, value/weight ratio) tuples
        let mut items: Vec<(usize, usize, f64)> = weights
            .iter()
            .zip(values.iter())
            .map(|(&w, &v)| {
                // Handle zero weights safely
                if w == 0 {
                    (w, v, f64::INFINITY)
                } else {
                    (w, v, v as f64 / w as f64)
                }
            })
            .collect();

        // Sort by value/weight ratio in descending order
        items.sort_by(|a, b| b.2.partial_cmp(&a.2).unwrap());

        let mut total_value = 0;
        let mut remaining_capacity = capacity;

        for (weight, value, _) in items {
            if remaining_capacity == 0 {
                break;
            }
            if weight <= remaining_capacity {
                remaining_capacity -= weight;
                total_value += value;
            }
        }

        total_value
    }
}

// Factory for creating solvers
pub struct KnapsackSolverFactory;

impl KnapsackSolverFactory {
    pub fn create_dynamic_programming_solver() -> DynamicProgrammingSolver {
        DynamicProgrammingSolver
    }

    pub fn create_branch_and_bound_solver() -> BranchAndBoundSolver {
        BranchAndBoundSolver
    }

    pub fn create_greedy_solver() -> GreedySolver {
        GreedySolver
    }
}

