			if i >= len(s.log) || s.log[i].Term != args.Entries[newEntriesIndex].Term {
				s.log = s.log[:i]
				break
			}
			newEntriesIndex++
		}

		// Append any new entries not already in the log
		if newEntriesIndex < len(args.Entries) {
			newEntries = args.Entries[newEntriesIndex:]
			s.log = append(s.log, newEntries...)
			s.logger.Printf("Server %d: appended %d new entries from leader %d\n", s.id, len(newEntries), args.LeaderID)
		}

		// Update commit index if leaderCommit > commitIndex
		if args.LeaderCommit > s.commitIndex {
			s.commitIndex = min(args.LeaderCommit, len(s.log)-1)
			s.applyCommittedEntries()
		}

		reply.Success = true
		reply.NextIndex = len(s.log)

		s.mu.Unlock()

		if !s.partition[peer] {
			s.appendEntriesRespCh[peer] <- reply
		}
	}
}

// listenForAppendEntriesResponse handles responses to AppendEntries RPCs
func (s *RaftServer) listenForAppendEntriesResponse(peer int) {
	for reply := range s.appendEntriesRespCh[peer] {
		s.mu.Lock()

		if reply.Term > s.currentTerm {
			// If RPC response contains term T > currentTerm: set currentTerm = T, convert to follower
			s.currentTerm = reply.Term
			s.state = Follower
			s.votedFor = -1
			s.leader = -1
			s.mu.Unlock()
			continue
		}

		if s.state == Leader && reply.Term == s.currentTerm {
			if reply.Success {
				// Update nextIndex and matchIndex for follower
				s.matchIndex[peer] = reply.NextIndex - 1
				s.nextIndex[peer] = reply.NextIndex

				// Check if we can commit any entries
				s.updateCommitIndex()
			} else {
				// Decrement nextIndex and retry
				s.nextIndex[peer] = reply.NextIndex
				s.logger.Printf("Server %d: AppendEntries to %d failed, setting nextIndex=%d\n", s.id, peer, s.nextIndex[peer])
			}
		}

		s.mu.Unlock()
	}
}

// updateCommitIndex checks if we can commit any entries
func (s *RaftServer) updateCommitIndex() {
	// Find the highest matchIndex that is replicated on a majority of servers
	for n := s.commitIndex + 1; n < len(s.log); n++ {
		if s.log[n].Term != s.currentTerm {
			continue
		}

		count := 1 // Leader has the entry
		for _, peer := range s.peers {
			if s.matchIndex[peer] >= n {
				count++
			}
		}

		if count > (len(s.peers)+1)/2 {
			s.commitIndex = n
			s.applyCommittedEntries()
		}
	}
}

