	s.mu.Lock()
	defer s.mu.Unlock()

	if s.isActive {
		return
	}

	s.logger.Printf("Server %d: RESTARTED\n", s.id)
	s.isActive = true
	s.state = Follower
	s.leader = -1
	s.resetElectionTimeout()
