// CreateCluster creates a new Raft cluster with the specified number of servers
func CreateCluster(numServers int) *Cluster {
	logFile, err := os.Create("raft_simulation.log")
	if err != nil {
		panic(err)
	}

	logger := log.New(logFile, "", log.Ldate|log.Ltime|log.Lmicroseconds)
	logger.Println("Starting Raft cluster simulation")

	servers := make([]*RaftServer, numServers)

	// Create all server IDs
	serverIDs := make([]int, numServers)
	for i := 0; i < numServers; i++ {
		serverIDs[i] = i
	}

	// Create and start each server
	for i := 0; i < numServers; i++ {
		peers := make([]int, 0)
		for j := 0; j < numServers; j++ {
			if j != i {
				peers = append(peers, j)
			}
		}

		servers[i] = NewRaftServer(i, peers, logger)
		servers[i].Start()
	}

	return &Cluster{
		servers: servers,
		logger:  logger,
	}
}

