# Rate limiting
class RateLimiter:
    def __init__(self, max_calls, period):
        self.max_calls = max_calls
        self.period = period
        self.calls = defaultdict(list)
        self.lock = threading.Lock()

    def is_allowed(self, client_id):
        now = time.time()
        with self.lock:
            # Remove expired timestamps
            self.calls[client_id] = [t for t in self.calls[client_id] if now - t < self.period]
            # Check if under limit
            if len(self.calls[client_id]) < self.max_calls:
                self.calls[client_id].append(now)
                return True
            return False

rate_limiter = RateLimiter(max_calls=10, period=60)  # 10 requests per minute

def rate_limit(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        client_id = request.remote_addr
        if not rate_limiter.is_allowed(client_id):
            abort(429)  # Too Many Requests
        return f(*args, **kwargs)
    return decorated_function

# LSH implementation with constant-time operations
class SecureLSH:
    def __init__(self, hash_size, dim, num_tables):
        self.hash_size = hash_size
        self.dim = dim
        self.num_tables = num_tables
        self.tables = [{} for _ in range(num_tables)]
        # Generate cryptographically secure random projections
        self.random_vectors = []
        for _ in range(num_tables):
            table_vectors = np.random.RandomState(secrets.randbits(32)).randn(hash_size, dim)
            self.random_vectors.append(table_vectors)

        # Secret key for HMAC operations
        self.secret_key = secrets.token_bytes(32)

    def _constant_time_hash(self, vector):
        """Generate hash using constant-time operations"""
        hashes = []

        for table_idx in range(self.num_tables):
            # Constant-time projection
            projections = np.zeros(self.hash_size)
            for i in range(self.hash_size):
                dot_product = 0.0
                for j in range(self.dim):
                    dot_product += self.random_vectors[table_idx][i][j] * vector[j]
                projections[i] = dot_product

            # Constant-time binary conversion
            binary_bits = []
            for proj in projections:
                # Use constant-time comparison
                bit = 1 if proj >= 0 else 0
                binary_bits.append(str(bit))

            # Create hash string
            hash_str = ''.join(binary_bits)

            # Use HMAC for secure, constant-time hash
            secure_hash = hmac.new(
                self.secret_key, 
                hash_str.encode('utf-8'), 
                hashlib.sha256
            ).digest()

            hashes.append(secure_hash)

        return hashes

    def insert(self, vector_id, vector):
        """Insert vector with constant-time hashing"""
        if len(vector) != self.dim:
            raise ValueError("Vector dimension mismatch")

        # Normalize vector for consistent processing
        vector = np.array(vector, dtype=np.float64)

        hashes = self._constant_time_hash(vector)

        for table_idx, hash_val in enumerate(hashes):
            if hash_val not in self.tables[table_idx]:
                self.tables[table_idx][hash_val] = []
            self.tables[table_idx][hash_val].append((vector_id, vector.copy()))

    def query(self, query_vector, k=10):
        """Query for nearest neighbors using constant-time operations"""
        if len(query_vector) != self.dim:
            raise ValueError("Query vector dimension mismatch")

        query_vector = np.array(query_vector, dtype=np.float64)
        hashes = self._constant_time_hash(query_vector)

        candidates = {}

        # Collect candidates from all hash tables
        for table_idx, hash_val in enumerate(hashes):
            if hash_val in self.tables[table_idx]:
                for vector_id, stored_vector in self.tables[table_idx][hash_val]:
                    if vector_id not in candidates:
                        candidates[vector_id] = stored_vector

        # Compute distances using constant-time operations
        results = []
        for vector_id, candidate_vector in candidates.items():
            distance = self._constant_time_distance(query_vector, candidate_vector)
            results.append((vector_id, distance))

        # Sort and return top k results
        results.sort(key=lambda x: x[1])
        return results[:k]

    def _constant_time_distance(self, vec1, vec2):
        """Compute Euclidean distance in constant time"""
        if len(vec1) != len(vec2):
            raise ValueError("Vector length mismatch")

        squared_sum = 0.0
        # Process all elements to maintain constant time
        for i in range(max(len(vec1), self.dim)):
            if i < len(vec1) and i < len(vec2):
                diff = vec1[i] - vec2[i]
                squared_sum += diff * diff
            else:
                # Dummy operation to maintain constant time
                dummy_diff = 0.0
                squared_sum += dummy_diff * dummy_diff

        return np.sqrt(squared_sum)

