        traders.emplace_back([&engine, &sideDist, &symbolDist, &priceDist, &qtyDist, &symbols, ordersPerTrader, &gen]() {
            std::mt19937 localGen(gen()); // Each thread gets its own generator

            for (int j = 0; j < ordersPerTrader; ++j) {
                Order::Type side = sideDist(localGen) ? Order::Type::BUY : Order::Type::SELL;
