            HttpServletRequest httpRequest) {

        // Validate TLS
        if (!httpRequest.isSecure()) {
            return ResponseEntity.badRequest().build();
        }

        TokenizeResponse response = paymentService.tokenizeCard(request);
        return ResponseEntity.ok(response);
    }

    @PostMapping("/webhook")
    public ResponseEntity<String> handleWebhook(
            @RequestBody Map<String, Object> payload,
            @RequestHeader("X-Signature") String signature,
            @RequestHeader("X-Timestamp") String timestamp,
            HttpServletRequest httpRequest) {

        // Validate TLS
        if (!httpRequest.isSecure()) {
            return ResponseEntity.badRequest().build();
        }

        WebhookRequest webhookRequest = new WebhookRequest(payload, signature, timestamp);

        if (webhookService.validateAndProcessWebhook(webhookRequest)) {
            return ResponseEntity.ok("Webhook processed successfully");
        } else {
            return ResponseEntity.badRequest().body("Invalid webhook signature or expired");
        }
    }
}

