	defer output.Close()

	// Get input streams
	streams, err := input.Streams()
	if err != nil {
		return err
	}

	// Set up video transcoding with CUDA hardware acceleration
	var videoStream transcode.VideoStream
	for _, stream := range streams {
		if stream.Type().IsVideo() {
			codecData := stream.(transcode.CodecData)
			videoStream, err = transcode.NewVideoStream(output, codecData)
			if err != nil {
				return err
			}

			// Configure output video properties
			videoStream.SetBitrate(task.Profile.Bitrate * 1000) // Convert kbps to bps

			// Calculate new dimensions while preserving aspect ratio
			origWidth := stream.(transcode.VideoCodecData).Width()
			origHeight := stream.(transcode.VideoCodecData).Height()
			newWidth, newHeight := calcResolution(origWidth, origHeight, task.Profile.Height)

			videoStream.SetWidth(newWidth)
			videoStream.SetHeight(newHeight)

			// Set encoder preset for quality/speed trade-off
			videoStream.SetPreset(task.Profile.Preset)

			// Enable hardware acceleration
			err = videoStream.SetupDecoder(ffmpeg.CUDA_HARDWARE)
			if err != nil {
				log.Printf("Warning: CUDA decoder initialization failed: %v, falling back to software", err)
			}

			// Configure zero-copy GPU pipeline when available
			videoStream.SetZeroCopy(true)
			break
		}
	}

	// Set up audio transcoding
	var audioStream transcode.AudioStream
	for _, stream := range streams {
		if stream.Type().IsAudio() {
			codecData := stream.(transcode.CodecData)
			audioStream, _ = transcode.NewAudioStream(output, codecData)
			// Keep audio at decent quality but optimize for streaming
			audioStream.SetBitrate(128000) // 128 kbps
			break
		}
	}

	// Create output context
	outputCtx := &transcode.OutputCtx{
		Ctx:         output,
		VideoStream: videoStream,
		AudioStream: audioStream,
	}

	// Process frames with zero-copy when possible
	frame := avutil.NewFrame()
	for {
		pkt, err := input.ReadPacket()
		if err != nil {
			break // End of file or error
		}

		if pkt.IsVideo() {
			// Decode video frame
			frame, err = videoStream.Decode(pkt)
			if err != nil {
				continue
			}

			// Encode with hardware acceleration when available
			encodedFrame, err := videoStream.Encode(frame, ffmpeg.CUDA_HARDWARE)
			if err != nil {
				continue
			}

			// Write encoded packet
			if err = outputCtx.WritePacket(encodedFrame); err != nil {
				continue
			}
		} else if pkt.IsAudio() && audioStream != nil {
			// Process audio
			aframe, err := audioStream.Decode(pkt)
			if err != nil {
				continue
			}

			encodedAudio, err := audioStream.Encode(aframe)
			if err != nil {
				continue
			}

			if err = outputCtx.WritePacket(encodedAudio); err != nil {
				continue
			}
		}
	}

	// Flush encoder buffers
	if err = videoStream.Flush(); err != nil {
		return err
	}

	if audioStream != nil {
		if err = audioStream.Flush(); err != nil {
			log.Printf("Warning: Error flushing audio stream: %v", err)
		}
	}

	return nil
}

// calcResolution calculates new dimensions preserving aspect ratio
func calcResolution(inputWidth, inputHeight, targetHeight int) (int, int) {
	aspectRatio := float64(inputWidth) / float64(inputHeight)
	newHeight := targetHeight
	newWidth := int(float64(newHeight) * aspectRatio)
	// Make width even for video codec requirements
	if newWidth % 2 != 0 {
		newWidth++
	}
	return newWidth, newHeight
}

// TranscodeManager orchestrates the transcoding process
type TranscodeManager struct {
	TaskChan     chan *TranscodingTask
	ResultChan   chan *TranscodingResult
	Workers      []*TranscodingWorker
	WorkerCount  int
	Ctx          context.Context
	CancelFunc   context.CancelFunc
	WG           sync.WaitGroup
}

// NewTranscodeManager creates a new transcoding manager
func NewTranscodeManager(workerCount int) *TranscodeManager {
	ctx, cancel := context.WithCancel(context.Background())

	if workerCount <= 0 {
		// Auto-configure worker count based on available CPUs
		workerCount = runtime.NumCPU()
		// Leave some CPU headroom for other operations
		if workerCount > 2 {
			workerCount = workerCount - 1
		}
	}

	return &TranscodeManager{
		TaskChan:    make(chan *TranscodingTask, 100),
		ResultChan:  make(chan *TranscodingResult, 100),
		Workers:     make([]*TranscodingWorker, workerCount),
		WorkerCount: workerCount,
		Ctx:         ctx,
		CancelFunc:  cancel,
	}
}

// Start initializes and starts the worker pool
func (tm *TranscodeManager) Start() {
	log.Printf("Starting transcoding manager with %d workers", tm.WorkerCount)

	// Create and start workers
	for i := 0; i < tm.WorkerCount; i++ {
		worker := NewTranscodingWorker(i, tm.TaskChan, &tm.WG)
		tm.Workers[i] = worker
		worker.Start()
	}

	// Start result handler
	tm.WG.Add(1)
	go tm.handleResults()
}

// Stop gracefully shuts down the transcoding system
func (tm *TranscodeManager) Stop() {
	log.Println("Stopping transcoding manager...")
	tm.CancelFunc()

	// Stop all workers
	for _, worker := range tm.Workers {
		if worker != nil {
			worker.Stop()
		}
	}

	// Close channels after all workers have stopped
	close(tm.TaskChan)

	// Wait for all goroutines to finish
	tm.WG.Wait()
	close(tm.ResultChan)

	log.Println("Transcoding manager stopped")
}

// SubmitTask sends a new transcoding task to the worker pool
func (tm *TranscodeManager) SubmitTask(inputPath, outputBase string, segmentID int) {
	for i, profile := range profiles {
		// Create unique output path for each profile
		outputPath := fmt.Sprintf("%s_%dp_%d.mp4", outputBase, profile.Height, segmentID)

		task := &TranscodingTask{
			InputPath:  inputPath,
			OutputPath: outputPath,
			Profile:    profile,
			SegmentID:  segmentID,
			ResultChan: tm.ResultChan,
		}

		select {
		case tm.TaskChan <- task:
			log.Printf("Submitted segment %d for %dp encoding", segmentID, profile.Height)
		case <-tm.Ctx.Done():
			return
		}
	}
}

// handleResults processes completed transcoding tasks
func (tm *TranscodeManager) handleResults() {
	defer tm.WG.Done()

	for {
		select {
		case <-tm.Ctx.Done():
			return
		case result, ok := <-tm.ResultChan:
			if !ok {
				return
			}

			if result.Error != nil {
				log.Printf("Transcoding error for segment %d to %dp: %v", 
					result.SegmentID, result.Profile.Height, result.Error)
			} else {
				// Track latency and alert on high values
				if result.Duration > 500*time.Millisecond {
					log.Printf("CRITICAL: High latency detected (%v) for segment %d to %dp", 
						result.Duration, result.SegmentID, result.Profile.Height)
				}

				// Here you would notify your streaming system that a new
				// segment is ready for a particular profile
				log.Printf("Completed segment %d for %dp profile in %v", 
					result.SegmentID, result.Profile.Height, result.Duration)
			}
		}
	}
}

// StreamHandler manages video stream ingestion and segmentation
type StreamHandler struct {
	TranscodeManager *TranscodeManager
	InputPath        string
	OutputDir        string
	SegmentDuration  time.Duration
	Ctx              context.Context
	CancelFunc       context.CancelFunc
	WG               sync.WaitGroup
}

// NewStreamHandler creates a new stream processor
func NewStreamHandler(transcodeMgr *TranscodeManager, inputPath, outputDir string) *StreamHandler {
	ctx, cancel := context.WithCancel(context.Background())

	return &StreamHandler{
		TranscodeManager: transcodeMgr,
		InputPath:        inputPath,
		OutputDir:        outputDir,
		SegmentDuration:  time.Second * 2, // 2-second segments for low latency
		Ctx:              ctx,
		CancelFunc:       cancel,
	}
}

// Start begins processing the input stream
func (sh *StreamHandler) Start() {
	sh.WG.Add(1)
	go sh.processStream()
}

// Stop gracefully shuts down the stream handler
func (sh *StreamHandler) Stop() {
	sh.CancelFunc()
	sh.WG.Wait()
}

// processStream handles stream segmentation and dispatching
func (sh *StreamHandler) processStream() {
	defer sh.WG.Done()

	// In a real implementation, this would use a live input stream
	// and segment it appropriately. For demonstration, we'll simulate
	// with a few segments.

	// Ensure output directory exists
	os.MkdirAll(sh.OutputDir, 0755)

	// In a real system, this would be your RTMP/WebRTC ingest point
	// Here we just simulate with a few segments for demonstration
	for i := 0; i < 10; i++ {
		select {
		case <-sh.Ctx.Done():
			return
		default:
			// In a real system, you would create segments from the live stream
			// For this example, we're using the same input file for all segments
			segmentBasePath := fmt.Sprintf("%s/segment_%d", sh.OutputDir, i)

			// Submit this segment for transcoding to all profiles
			sh.TranscodeManager.SubmitTask(sh.InputPath, segmentBasePath, i)

			// Wait for segment duration before processing next segment
			// In a real system, this would be synchronized with actual stream timing
			time.Sleep(sh.SegmentDuration)
		}
	}
}

